import React, { useState, useEffect } from "react";
import { Chart } from "chart.js/auto";

function Admin() {
  const [stats, setStats] = useState({ good: 0, bad: 0 });

  const setWeight = async (value) => {
    await fetch("http://localhost:3000/set-weight", {
      method: "POST",
      body: JSON.stringify({ weight: value }),
      headers: { "Content-Type": "application/json" }
    });
  };

  const loadStats = async () => {
    const res = await fetch("http://localhost:3000/stats");
    const data = await res.json();
    setStats(data);
  };

  useEffect(() => {
    loadStats();
  }, []);

  useEffect(() => {
    const ctx = document.getElementById("chart");
    new Chart(ctx, {
      type: "pie",
      data: {
        labels: ["Good", "Bad"],
        datasets: [{
          data: [stats.good, stats.bad]
        }]
      }
    });
  }, [stats]);

  return (
    <div>
      <h2>Admin Dashboard</h2>
      <input type="range" min="0" max="100" onChange={(e) => setWeight(e.target.value)} />
      <canvas id="chart"></canvas>
    </div>
  );
}

export default Admin;
